INSERT INTO `email_templates` (`id`, `name`, `description`, `subject`, `body`, `is_global`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'Demande standard de documents', 'Email général pour collecter documents et accès', '[CGI Mission Preparation] Document and Access Request', 'Dear {{recipient_name}},\r\n\r\nI hope this message finds you well.\r\n\r\nAs part of the preparation for our upcoming consulting mission, I am reaching out to request the following items, which are needed to ensure a smooth and timely start to our collaboration.\r\n\r\n{{task_list}}\r\n\r\nCould you please provide these items by {{deadline}}? Should any item require clarification, please do not hesitate to contact me directly.\r\n\r\nThank you in advance for your cooperation. We look forward to working with you.\r\n\r\nBest regards,\r\n{{consultant_name}}\r\nCGI', 1, 1, '2026-03-14 16:26:53', '2026-03-14 16:26:53'),
(2, 'Demande d\'accès et identifiants', 'Email ciblé pour les accès informatiques et identifiants', '[CGI Mission Preparation] Access and Credentials Setup', 'Dear {{recipient_name}},\r\n\r\nI am writing to request the setup of the accesses and credentials required for my upcoming consulting mission.\r\n\r\n{{task_list}}\r\n\r\nTimely provisioning of these accesses is essential to meet our agreed project start date. If there is an IT request process I should follow on my side, please let me know and I will complete it immediately.\r\n\r\nThank you for your support.\r\n\r\nBest regards,\r\n{{consultant_name}}\r\nCGI', 1, 1, '2026-03-14 16:26:53', '2026-03-14 16:26:53'),
(3, 'Relance — éléments manquants', 'Email de relance poli pour les éléments en attente', '[REMINDER] Outstanding Items — CGI Mission Preparation', 'Dear {{recipient_name}},\r\n\r\nI hope you are doing well. I am following up on my previous request regarding items needed for our upcoming mission.\r\n\r\nThe following items are still outstanding:\r\n\r\n{{task_list}}\r\n\r\nAs our project start date is approaching, I would greatly appreciate your assistance in providing these items by {{deadline}}.\r\n\r\nPlease do not hesitate to reach out if you need any clarification from my side.\r\n\r\nThank you,\r\n{{consultant_name}}\r\nCGI', 1, 1, '2026-03-14 16:26:53', '2026-03-14 16:26:53'),
(4, 'Lancement de mission — email complet', 'Premier contact complet couvrant tous les aspects de préparation', '[CGI Mission] Pre-Start Preparation Checklist', 'Dear {{recipient_name}},\r\n\r\nI am pleased to confirm my upcoming consulting mission and would like to begin the administrative and technical preparation to ensure a successful start.\r\n\r\nTo have everything in place, I would be grateful if you could arrange the following:\r\n\r\n{{task_list}}\r\n\r\nA few additional points:\r\n- Please confirm the preferred method for document sharing (secure portal, email, etc.)\r\n- Let me know if any items require internal approval or procurement processes\r\n- I remain available for a brief call to clarify any points at your convenience\r\n\r\nTarget date for all items: {{deadline}}\r\n\r\nThank you very much for your collaboration.\r\n\r\nBest regards,\r\n{{consultant_name}}\r\nConsultant — CGI', 1, 1, '2026-03-14 16:26:53', '2026-03-14 16:26:53');

