--
-- Déchargement des données de la table `projects`
--

INSERT INTO `projects` (`id`, `consultant_id`, `client_id`, `name`, `description`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, NULL, 'Projet Data Platform', 'Lettre de mission — Projet Data Platform\n\nClient : ClientCorp\nPrestataire : CGI\nConsultant : Alice Martin\nDate : 12 mars 2026\n\n1. Objet de la mission\n\nLa présente lettre de mission définit les conditions dans lesquelles CGI interviendra pour accompagner ClientCorp dans la mise en place d’une plateforme de données destinée à améliorer la gestion et l’analyse des données opérationnelles.\n\n2. Description des prestations\n\nLe consultant interviendra sur les activités suivantes :\n\nAnalyse de l’architecture existante\n\nMise en place d’une plateforme de traitement de données\n\nDéploiement d’outils d’analyse et de reporting\n\nDocumentation technique et transfert de compétences\n\n3. Documents et informations requis\n\nAfin de mener à bien la mission, le client devra fournir les éléments suivants :\n\nAccord de confidentialité (NDA) signé\n\nDescription de l’architecture informatique actuelle\n\nAccès VPN ou accès distant sécurisé aux systèmes internes\n\nCréation d’un compte Active Directory pour le consultant\n\nAccès aux bases de données nécessaires au projet\n\nDocumentation technique existante sur les flux de données\n\nPolitique de sécurité informatique du client\n\nCoordonnées du chef de projet côté client\n\nCoordonnées du responsable sécurité informatique\n\n4. Accès et habilitations\n\nLe client s’engage à fournir :\n\nun badge d’accès aux locaux si nécessaire\n\nles identifiants permettant l’accès aux environnements de développement et de test\n\nles droits nécessaires pour consulter les bases de données utiles au projet\n\n5. Durée de la mission\n\nLa mission débutera le 1er avril 2026 pour une durée estimée de 6 mois.\n\n6. Confidentialité\n\nToutes les informations échangées dans le cadre de la mission sont strictement confidentielles.', 'draft', '2026-03-14 13:01:33', '2026-03-14 13:01:33'),
(2, 2, NULL, 'Projet Data Platform', 'Lettre de mission — Projet Data Platform\n\nClient : ClientCorp\nPrestataire : CGI\nConsultant : Alice Martin\nDate : 12 mars 2026\n\n1. Objet de la mission\n\nLa présente lettre de mission définit les conditions dans lesquelles CGI interviendra pour accompagner ClientCorp dans la mise en place d’une plateforme de données destinée à améliorer la gestion et l’analyse des données opérationnelles.\n\n2. Description des prestations\n\nLe consultant interviendra sur les activités suivantes :\n\nAnalyse de l’architecture existante\n\nMise en place d’une plateforme de traitement de données\n\nDéploiement d’outils d’analyse et de reporting\n\nDocumentation technique et transfert de compétences\n\n3. Documents et informations requis\n\nAfin de mener à bien la mission, le client devra fournir les éléments suivants :\n\nAccord de confidentialité (NDA) signé\n\nDescription de l’architecture informatique actuelle\n\nAccès VPN ou accès distant sécurisé aux systèmes internes\n\nCréation d’un compte Active Directory pour le consultant\n\nAccès aux bases de données nécessaires au projet\n\nDocumentation technique existante sur les flux de données\n\nPolitique de sécurité informatique du client\n\nCoordonnées du chef de projet côté client\n\nCoordonnées du responsable sécurité informatique\n\n4. Accès et habilitations\n\nLe client s’engage à fournir :\n\nun badge d’accès aux locaux si nécessaire\n\nles identifiants permettant l’accès aux environnements de développement et de test\n\nles droits nécessaires pour consulter les bases de données utiles au projet\n\n5. Durée de la mission\n\nLa mission débutera le 1er avril 2026 pour une durée estimée de 6 mois.\n\n6. Confidentialité\n\nToutes les informations échangées dans le cadre de la mission sont strictement confidentielles.', 'draft', '2026-03-14 13:19:33', '2026-03-14 13:19:33'),
(3, 1, NULL, 'Test Data 2', 'Mission cool', 'draft', '2026-03-15 12:29:45', '2026-03-15 12:29:45');

