--
-- Structure de la vue `document_versions`
--
DROP TABLE IF EXISTS `document_versions`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `document_versions`  AS SELECT `d`.`id` AS `id`, `d`.`task_id` AS `task_id`, `d`.`uploaded_by` AS `uploaded_by`, `d`.`filename` AS `filename`, `d`.`mime_type` AS `mime_type`, `d`.`file_data` AS `file_data`, `d`.`file_size` AS `file_size`, `d`.`created_at` AS `created_at`, `t`.`title` AS `task_title`, `t`.`checklist_id` AS `checklist_id`, `u`.`name` AS `uploader_name` FROM ((`documents` `d` join `tasks` `t` on(`t`.`id` = `d`.`task_id`)) join `users` `u` on(`u`.`id` = `d`.`uploaded_by`)) ;

